import CodepageEncoder from "../../CodepageEncoder/dist/codepage-encoder.mjs";

const encodings = [
  ["CP437", "cp437"],
  ["STAR_KATAKANA", "star/katakana"],
  ["CP850", "cp850"],
  ["CP860", "cp860"],
  ["CP863", "cp863"],
  ["CP865", "cp865"],
  ["WINDOWS_1252", "windows1252"],
  ["CP866", "cp866"],
  ["CP852", "cp852"],
  ["CP858", "cp858"],
  ["THAI42", "thai42"],
  ["THAI11", "thai11"],
  ["THAI13", "thai13"],
  ["THAI14", "thai14"],
  ["THAI16", "thai16"],
  ["THAI18", "thai18"],
];

const lines = [
  "// Generated by gadget/tools/generate-codepage-tables.mjs from",
  "// CodepageEncoder 3.x. Do not edit this file by hand.",
  "",
];

for (const [constant, encoding] of encodings) {
  const codepoints = CodepageEncoder.getEncoding(encoding).codepoints;
  if (codepoints.length !== 256) throw new Error(`${encoding} did not produce 256 codepoints`);

  lines.push(`// CodepageEncoder encoding: ${encoding}`);
  lines.push(`pub(super) const ${constant}: [u32; 256] = [`);
  for (let offset = 0; offset < codepoints.length; offset += 8) {
    lines.push(`    ${codepoints.slice(offset, offset + 8).join(", ")},`);
  }
  lines.push("];", "");
}

const output = new URL("../src/codepage_tables.rs", import.meta.url);
await Bun.write(output, `${lines.join("\n")}\n`);

const formatter = Bun.spawn(["rustfmt", output.pathname], { stderr: "inherit" });
if (await formatter.exited) throw new Error("rustfmt failed");
